<template>
  <section class="territory-view">
    <div class="map-viewport" @pointerdown="startPan" @pointermove="pan" @pointerup="endPan" @pointercancel="endPan" @wheel.prevent="onWheel">
      <div class="strategic-map" :style="mapTransform">
        <img class="terrain-art" src="/assets/territory/wanxiang-territory-map.svg" alt="万象仙乡山河地图" draggable="false" />
        <svg class="supply-lines" viewBox="0 0 100 100" preserveAspectRatio="none" aria-hidden="true">
          <line v-for="route in routes" :key="route.id" :x1="route.from.x" :y1="route.from.y" :x2="route.to.x" :y2="route.to.y" :class="{ active: route.active, frontier: route.frontier }" />
        </svg>
        <div v-for="node in store.nodes.filter(n => n.status === 'owned')" :key="`domain-${node.id}`" class="domain" :style="{ left:`${node.x}%`, top:`${node.y}%` }" />
        <button v-for="node in store.nodes" :key="node.id" class="territory-node" :class="[node.status,{selected:node.id===store.selectedId,capital:node.kind==='capital',reachable:store.isReachable(node)}]" :style="{left:`${node.x}%`,top:`${node.y}%`}" @pointerdown.stop @click.stop="select(node.id)">
          <span class="node-building"><span>{{ icons[node.kind] }}</span></span>
          <span class="node-copy"><b>{{ node.name }}</b><small>Lv.{{ node.level }} · {{ node.status === 'neutral' ? `守军${node.garrison}` : `驻防${node.garrison}` }}</small></span>
          <i v-if="node.status==='contested'" class="alarm">!</i>
        </button>
      </div>
      <div class="mist-edge top"/><div class="mist-edge bottom"/>
    </div>

    <header class="top-hud glass">
      <div class="brand"><span class="seal">乡</span><div><p>万象仙乡</p><h1>山河领地</h1></div></div>
      <div class="resource-hud">
        <div><span>木材</span><b>{{ store.resources.wood }}</b><small>+{{ store.incomePerHour.wood }}/时</small></div>
        <div><span>石料</span><b>{{ store.resources.stone }}</b><small>+{{ store.incomePerHour.stone }}/时</small></div>
        <div><span>灵晶</span><b>{{ store.resources.spirit }}</b><small>+{{ store.incomePerHour.spirit }}/时</small></div>
        <div><span>行动力</span><b>{{ store.actionPoints }}/{{ store.maxActionPoints }}</b><small>15分钟+1</small></div>
      </div>
      <div class="top-actions"><button title="返回仙乡" @click="leaveTerritory"><House :size="16"/><span class="leave-label">返回仙乡</span></button><button title="恢复全图" @click="resetView"><Maximize2 :size="16"/></button><button class="raid-button" :disabled="store.raidCooldownSeconds>0 || store.nodes.some(n=>n.status==='contested')" @click="raid"><ShieldAlert :size="16"/>{{ store.nodes.some(n=>n.status==='contested') ? '先回援' : store.raidCooldownSeconds>0 ? `${Math.ceil(store.raidCooldownSeconds/60)}分后演练` : '敌袭演练' }}</button></div>
    </header>

    <aside class="army-panel glass">
      <div class="panel-title"><Swords :size="16"/><span>万象军府</span></div>
      <div class="army-numbers"><div><small>兵力</small><b>{{ store.army.troops }}/{{ store.army.maxTroops }}</b></div><div><small>士气</small><b>{{ store.army.morale }}</b></div><div><small>势力</small><b>{{ store.totalPower }}</b></div></div>
      <div class="progress"><i :style="{width:`${Math.round(store.army.troops/store.army.maxTroops*100)}%`}"/></div>
      <p class="stance-label">出征阵型 <span>破阵克奇袭 · 镇守克破阵 · 奇袭克镇守</span></p>
      <div class="stances"><button v-for="stance in stances" :key="stance.id" :class="{active:store.army.stance===stance.id}" @click="setStance(stance.id)"><b>{{ stance.icon }}</b><span>{{ stance.name }}</span></button></div>
      <button class="wide-action" @click="recruit"><Users :size="14"/>征募最多40兵</button>
    </aside>

    <aside v-if="selected" class="node-panel glass">
      <div class="selected-head"><span class="selected-icon">{{ icons[selected.kind] }}</span><div><h2>{{ selected.name }}</h2><p>{{ kindLabels[selected.kind] }} · Lv.{{ selected.level }}</p></div><span class="status" :class="selected.status">{{ statusLabels[selected.status] }}</span></div>
      <p class="description">{{ descriptions[selected.kind] }}</p>
      <div class="node-stats"><div><span>守军</span><b>{{ selected.garrison }}</b></div><div><span>每时产出</span><b>木{{ selected.income.wood*selected.level }} 石{{ selected.income.stone*selected.level }} 灵{{ selected.income.spirit*selected.level }}</b></div></div>
      <div v-if="selected.status==='neutral'" class="supply-note" :class="{blocked:!store.isReachable(selected)}"><Route :size="14"/>{{ store.isReachable(selected) ? '供给线畅通，可以消耗2行动力出征。' : '尚未与己方领土相邻，需先扩张供给线。' }}</div>
      <div v-if="selected.status==='contested'" class="supply-note danger"><ShieldAlert :size="14"/>敌军正在围攻该据点，立即回援。</div>
      <div class="node-actions">
        <button v-if="selected.status==='neutral'" class="primary" :disabled="!store.isReachable(selected)" @click="march"><Swords :size="15"/>出征攻取</button>
        <button v-if="selected.status==='contested'" class="danger-button" @click="resolve"><ShieldCheck :size="15"/>调兵回援</button>
        <template v-if="selected.status==='owned'"><button class="primary" @click="upgrade"><ArrowUpCircle :size="15"/>升级据点</button><button @click="fortify"><Castle :size="15"/>增筑驻防</button></template>
      </div>
    </aside>

    <section class="bottom-hud glass">
      <div class="territory-progress"><span>山河控制</span><b>{{ store.territoryProgress }}%</b><div><i :style="{width:`${store.territoryProgress}%`}"/></div><small>{{ store.ownedNodes.length }}/{{ store.nodes.length }} 据点</small></div>
      <div class="event-line"><span>◆</span><p>{{ store.lastAction }}</p></div>
      <button class="report-toggle" @click="showReports=!showReports"><ScrollText :size="15"/>战报 {{ store.reports.length }}</button>
    </section>

    <section v-if="showReports" class="reports glass">
      <div class="report-head"><b>山河战报</b><button @click="showReports=false"><X :size="15"/></button></div>
      <p v-if="!store.reports.length" class="empty">尚无战报，第一次出征后将在这里记录。</p>
      <article v-for="report in store.reports" :key="report.id" :class="report.result"><div><b>{{ report.title }}</b><time>{{ formatTime(report.at) }}</time></div><p>{{ report.detail }}</p></article>
    </section>

    <div class="zoom-hud glass"><button @click="zoom(.1)"><Plus :size="15"/></button><span>{{ Math.round(zoomLevel*100) }}%</span><button @click="zoom(-.1)"><Minus :size="15"/></button></div>
    <div class="map-hint">拖动山河 · 滚轮缩放 · 点击据点指挥</div>
  </section>
</template>

<script setup lang="ts">
import { computed,onMounted,onUnmounted,ref } from "vue";
import { ArrowUpCircle,Castle,House,Maximize2,Minus,Plus,Route,ScrollText,ShieldAlert,ShieldCheck,Swords,Users,X } from "lucide-vue-next";
import { useRouter } from "vue-router";
import { useTerritoryStore,type ArmyStance,type TerritoryKind } from "@/stores/useTerritoryStore";
import { useSaveStore } from "@/stores/useSaveStore";
