const descriptions:Record<TerritoryKind,string>={capital:"山河中枢与军府所在，连接四方供给线。",farm:"层叠灵田与林场，持续供应领地建设木材。",mine:"深入地脉的矿场，是城防与升级的石料来源。",spirit:"灵潮汇聚的灵眼，稳定凝聚战略灵晶。",watch:"控制隘口、强化全军战力与边境预警。",ruins:"高风险古代遗址，守军强大但资源回报丰厚。"};
const statusLabels={owned:"我方",neutral:"中立",contested:"告急"};
const stances:{id:ArmyStance;name:string;icon:string}[]=[{id:"assault",name:"破阵",icon:"锋"},{id:"guard",name:"镇守",icon:"盾"},{id:"flank",name:"奇袭",icon:"翼"}];
const routes=computed(()=>{const seen=new Set<string>();return store.nodes.flatMap(from=>from.links.flatMap(targetId=>{const to=store.nodes.find(n=>n.id===targetId);const id=[from.id,targetId].sort().join(":");if(!to||seen.has(id))return[];seen.add(id);return[{id,from,to,active:from.status==="owned"&&to.status==="owned",frontier:(from.status==="owned"&&to.status==="neutral")||(to.status==="owned"&&from.status==="neutral")}];}));});
const mapTransform=computed(()=>({transform:`translate(${offset.value.x}px,${offset.value.y}px) scale(${zoomLevel.value})`}));
const save=()=>saveStore.autoSave();const leaveTerritory=()=>{if(store.tick())save();router.push({name:"home"});};const select=(id:string)=>store.select(id);const setStance=(s:ArmyStance)=>{store.setStance(s);save();};const march=()=>{if(store.march(store.selectedId))save();};const recruit=()=>{if(store.recruit())save();};const fortify=()=>{if(store.fortify(store.selectedId))save();};const upgrade=()=>{if(store.upgrade(store.selectedId))save();};const raid=()=>{if(store.triggerRaid())save();};const resolve=()=>{if(store.resolveRaid(store.selectedId))save();};
const zoom=(n:number)=>zoomLevel.value=Math.min(1.65,Math.max(.82,zoomLevel.value+n));const resetView=()=>{zoomLevel.value=1;offset.value={x:0,y:0};};const onWheel=(e:WheelEvent)=>zoom(e.deltaY>0?-.08:.08);const startPan=(e:PointerEvent)=>{dragging.value=true;pointerStart.value={x:e.clientX,y:e.clientY};offsetStart.value={...offset.value};(e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);};const pan=(e:PointerEvent)=>{if(!dragging.value)return;offset.value={x:offsetStart.value.x+e.clientX-pointerStart.value.x,y:offsetStart.value.y+e.clientY-pointerStart.value.y};};const endPan=()=>dragging.value=false;const formatTime=(t:number)=>new Date(t).toLocaleTimeString("zh-CN",{hour:"2-digit",minute:"2-digit"});
let timer:number|undefined;onMounted(()=>{if(store.tick())save();timer=window.setInterval(()=>{if(store.tick())save();},60000);});onUnmounted(()=>{if(timer)window.clearInterval(timer);if(store.tick())save();});
</script>

